import React, { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import StatusPill from "../components/StatusPill";
import { fetchExpenses } from "../api/expenses";
import { formatCurrency } from "../utils/format";

const fallbackExpenses = [
  {
    id: 1,
    vendor: "Aurora Travel",
    date: "Feb 14, 2026",
    amount: "$2,430",
    status: "Approved",
  },
  {
    id: 2,
    vendor: "City Bistro",
    date: "Feb 13, 2026",
    amount: "$214",
    status: "Pending",
  },
  {
    id: 3,
    vendor: "Northwind Cloud",
    date: "Feb 11, 2026",
    amount: "$1,180",
    status: "Rejected",
  },
  {
    id: 4,
    vendor: "Studio Nine",
    date: "Feb 10, 2026",
    amount: "$640",
    status: "Approved",
  },
];

const History = () => {
  const [expenses, setExpenses] = useState([]);
  const [status, setStatus] = useState({ loading: true, error: "" });

  const safeValue = (value) => {
    if (value === null || value === undefined) {
      return "";
    }
    return String(value).replace(/"/g, '""');
  };

  const buildCsv = (rows) => {
    const headers = [
      "id",
      "vendor",
      "date",
      "amount",
      "status",
      "category",
      "payment_method",
      "receipt",
    ];
    const lines = rows.map((expense) => {
      const values = [
        expense.id,
        expense.merchant || expense.vendor || "",
        expense.expense_date || expense.date || "",
        expense.amount || "",
        expense.status || "pending",
        expense.category_name || expense.category || "",
        expense.payment_method || "",
        expense.receipt_file || "",
      ];
      return values.map((value) => `"${safeValue(value)}"`).join(",");
    });
    return [headers.join(","), ...lines].join("\n");
  };

  const handleExport = () => {
    const data = expenses.length ? expenses : fallbackExpenses;
    if (!data.length) {
      setStatus((prev) => ({ ...prev, error: "No expenses to export." }));
      return;
    }
    const csv = buildCsv(data);
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = "smartspend-expense-report.csv";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  useEffect(() => {
    fetchExpenses()
      .then((data) => {
        setExpenses(data);
        setStatus({ loading: false, error: "" });
      })
      .catch(() => setStatus({ loading: false, error: "Unable to load expenses." }));
  }, []);

  return (
    <div className="page">
      <PageHeader
        title="Expense history"
        subtitle="Track every submission, receipt, and decision." 
        actions={
          <button className="button" type="button" onClick={handleExport}>
            Export report
          </button>
        }
      />
      {status.error ? <div className="alert">{status.error}</div> : null}
      <div className="card">
        <table className="table">
          <thead>
            <tr>
              <th>Vendor</th>
              <th>Date</th>
              <th>Amount</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {(expenses.length ? expenses : fallbackExpenses).map((expense) => (
              <tr key={expense.id}>
                <td>{expense.merchant || expense.vendor}</td>
                <td>{expense.expense_date || expense.date}</td>
                <td>{formatCurrency(expense.amount)}</td>
                <td>
                  <StatusPill status={expense.status || "Pending"} />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className="grid grid--two">
        <div className="card">
          <h3>Receipt compliance</h3>
          <p className="stat-card__label">
            92% of expenses include receipts. Focus on travel and meals to
            reach 98% compliance.
          </p>
        </div>
        <div className="card">
          <h3>Policy summary</h3>
          <div className="list">
            <div className="list-item">
              <strong>Out of policy</strong>
              <span className="chip">3 this month</span>
            </div>
            <div className="list-item">
              <strong>Auto-approved</strong>
              <span className="chip">61%</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default History;
